// Vectorized kernel using float4 for better memory bandwidth utilization with grid-stride loop
__global__ void hardsigmoid_kernel_vectorized(const float* __restrict__ input, 
                                              float* __restrict__ output, 
                                              int size) {
    // Each thread processes multiple groups of 4 elements using grid-stride loop
    const int elements_per_thread = 4;
    const int thread_id = blockIdx.x * blockDim.x + threadIdx.x;
    const int total_threads = blockDim.x * gridDim.x;
    const int stride = total_threads * elements_per_thread;

    // Start processing from this thread's starting position
    int base_idx = thread_id * elements_per_thread;

    // Grid-stride loop for robustness against launch configuration changes
    while (base_idx < size) {
        // Check if we can process a full float4
        if (base_idx + elements_per_thread - 1 < size) {
            // Load 4 elements at once using float4
            float4 in_vec = *reinterpret_cast<const float4*>(&input[base_idx]);
            float4 out_vec;

            // Apply HardSigmoid to each element: max(0, min(1, (x + 3) / 6))
            const float one_sixth = 1.0f / 6.0f;
            const float half = 0.5f;

            out_vec.x = fmaxf(0.0f, fminf(1.0f, __fmaf_rd(in_vec.x, one_sixth, half)));
            out_vec.y = fmaxf(0.0f, fminf(1.0f, __fmaf_rd(in_vec.y, one_sixth, half)));
            out_vec.z = fmaxf(0.0f, fminf(1.0f, __fmaf_rd(in_vec.z, one_sixth, half)));
            out_vec.w = fmaxf(0.0f, fminf(1.0f, __fmaf_rd(in_vec.w, one_sixth, half)));

            // Store 4 elements at once
            *reinterpret_cast<float4*>(&output[base_idx]) = out_vec;
        } else {
